import React, { useState, useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useParams } from "react-router-dom";
import { getUserById, updateUserProfile } from "../../features/UserList/UserListSlice";
import { toast } from "react-toastify";
import { uploadImg } from "../../features/upload/uploadSlice";

function UserProfile() {
  const [isEditing, setIsEditing] = useState(false);
  const [profileInfo, setProfileInfo] = useState({
    firstname: "",
    lastname: "",
    mobile: "",
    email: "",
    ProfilePicture: [],
  });
  const [previewImage, setPreviewImage] = useState("");
  const dispatch = useDispatch();

  const { id } = useParams();  

  const { isError, isSuccess, Eachusers } = useSelector((state) => state.userList);
  const userState = Eachusers?.getaUser || {};

  // Fetch the user data when the component mounts or UserId changes
  useEffect(() => {
    if (id) {
      dispatch(getUserById(id));
    }
  }, [id, dispatch]);

  useEffect(() => {
    if (userState && !isEditing) {
      setProfileInfo({
        firstname: userState.firstname || "",
        lastname: userState.lastname || "",
        mobile: userState.mobile || "",
        email: userState.email || "",
        ProfilePicture: userState.ProfilePicture ? [userState.ProfilePicture.secure_url] : [],
      });
      setPreviewImage(userState.ProfilePicture?.secure_url || "");
    }
  }, [userState, isEditing]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setProfileInfo((prevInfo) => ({ ...prevInfo, [name]: value }));
  };

  const handleEditToggle = () => {
    if (isEditing) {
      dispatch(updateUserProfile({ id: userState._id, profileInfo }))
        .then(() => {
          toast.success("Profile updated successfully!");
          dispatch(getUserById(userState._id));
        })
        .catch(() => toast.error("Failed to update profile."));
    }
    setIsEditing(!isEditing);
  };

  const handleImageUpload = (e) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      const formData = new FormData();
      for (let i = 0; i < files.length; i++) {
        formData.append("multiple_image", files[i]);
      }
      dispatch(uploadImg(formData))
        .then((res) => {
          const uploadedImages = res.payload?.map((file) => file.path);
          setProfileInfo((prevInfo) => ({
            ...prevInfo,
            ProfilePictures: uploadedImages,
          }));
          toast.success("Images uploaded successfully!");
        })
        .catch((err) => {
          console.error("Upload failed:", err);
          toast.error("Failed to upload images.");
        });
    } else {
      toast.error("No files selected.");
    }
  };

  useEffect(() => {
    if (isError) {
      toast.error("An error occurred while fetching or updating data.");
    }
  }, [isError]);

  return (
    <div className="min-h-screen bg-cover bg-center bg-no-repeat bg-gray-200">
      <h1 className="w-full max-h-20 text-white bg-black text-3xl font-semibold p-4">User Profile</h1>
      <div className="container mx-auto mt-20 bg-white p-6 rounded-lg shadow-lg">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 text-gray-700">
          {/* Photo Section */}
          <div className="flex flex-col items-center gap-4 pt-20">
            <img
              className="w-64 h-64 rounded-2xl shadow-md"
              src={previewImage || "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTd-odagfgTkIJAJFY0UmNVAxC_pemR52Czyg&s"}
              alt="Profile"
              onError={(e) => {
                e.target.onerror = null;
                e.target.src = "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTd-odagfgTkIJAJFY0UmNVAxC_pemR52Czyg&s";
              }}
            />
            <label
              htmlFor="input-file"
              className="bg-gray-700 text-sm font-bold py-2 px-4 rounded cursor-pointer text-white hover:bg-gray-600"
            >
              Change Photo
            </label>
            <input
              type="file"
              accept="image/*"
              id="input-file"
              className="hidden"
              multiple
              onChange={handleImageUpload} 
            />
          </div>

          {/* Info Section */}
          <div className="flex flex-col gap-4">
            <h2 className="text-4xl font-extrabold ">Personal Information</h2>

            {/* First Name */}
            <div>
              <label className="block text-lg font-bold">First Name:</label>
              <input
                type="text"
                name="firstname"
                value={profileInfo.firstname}
                onChange={handleChange}
                readOnly={!isEditing}
                className={`w-full mt-1 p-2 rounded border ${isEditing ? "bg-white" : "bg-gray-100"}`}
              />
            </div>

            {/* Last Name */}
            <div>
              <label className="block text-lg font-bold">Last Name:</label>
              <input
                type="text"
                name="lastname"
                value={profileInfo.lastname}
                onChange={handleChange}
                readOnly={!isEditing}
                className={`w-full mt-1 p-2 rounded border ${isEditing ? "bg-white" : "bg-gray-100"}`}
              />
            </div>

            {/* ID (non-editable) */}
            <div>
              <label className="block text-lg font-bold">ID:</label>
              <input
                type="text"
                name="id"
                value={userState._id || ""}
                readOnly
                className="w-full mt-1 p-2 rounded border bg-gray-100"
              />
            </div>

            {/* Role */}
            <div>
              <label className="block text-lg font-bold">Role:</label>
              <input
                type="text"
                name="role"
                value={userState.role || ""}
                readOnly
                className="w-full mt-1 p-2 rounded border bg-gray-100"
              />
            </div>

            <h2 className="text-3xl font-extrabold mt-6">Contact Details</h2>

            {/* Phone Number */}
            <div>
              <label className="block text-lg font-bold">Phone Number:</label>
              <input
                type="text"
                name="mobile"
                value={profileInfo.mobile}
                onChange={handleChange}
                readOnly={!isEditing}
                className={`w-full mt-1 p-2 rounded border ${isEditing ? "bg-white" : "bg-gray-100"}`}
              />
            </div>

            {/* Email */}
            <div>
              <label className="block text-lg font-bold">Email:</label>
              <input
                type="email"
                name="email"
                value={profileInfo.email}
                onChange={handleChange}
                readOnly={!isEditing}
                className={`w-full mt-1 p-2 rounded border ${isEditing ? "bg-white" : "bg-gray-100"}`}
              />
            </div>
          </div>
        </div>

        <div className="mt-6 flex justify-end">
          <button
            onClick={handleEditToggle}
            className="bg-blue-500 text-white py-2 px-4 rounded hover:bg-blue-600"
          >
            {isEditing ? "Save Changes" : "Edit Profile"}
          </button>
        </div>
      </div>
    </div>
  );
}

export default UserProfile;
